VALUES
  ('social-worker-moex-07720', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在學校社會工作實務上，社會工作人員的職責是協助社區居民去瞭解學校教育方案，改變那些不能滿足 學生需要的社區情境，這是採取何種工作模式？', '["傳統臨床模式", "學校變遷模式", "社會互動模式", "社區學校模式"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07721', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在工業社會工作實務上，社會工作人員協助組織與員工進行行政中立方案、公平政策發展方案，以及預 防工作歧視方案等肯定行動方案，這是屬於何種類型服務方案？', '["人力資源方案", "諮商方案", "社會及社群變遷方案", "多重服務方案"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07722', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在矯治社會工作上，採取一種以住宿為中心的型態，來收容剛出獄或輕犯者，以擔任機構處遇與社區生 活的中途轉換站，並透過各種服務，協助其及早適應社區。這是屬於何種社區處遇方式？', '["寄養家庭（foster home）", "中途之家（halfway house）", "觀護制度（probation）", "更生保護（after care）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07723', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在醫務社會工作中，下列何者不屬於社會工作人員在健康照護中的角色？', '["評估病患心理和環境的優缺點", "在服務輸送上與團隊合作，以確保每位團隊成員的知識和技術，能被善加利用", "協助家屬合作參與治療，並協助病患善用醫療服務", "疾病診斷與研擬治療計畫"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07724', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會服務機構在決定分配稀少資源時，主張弱勢族群或受壓迫的社區應優先給予資源或服務的提供。請 問這是採取何種分配正義的標準？', '["平等（equality）", "需要（need）", "補償（compensation）", "貢獻的多寡（contribution）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07725', 'social-worker', 'social-worker-moex-099-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在社工專業倫理上，社會工作人員與案主的關係，不可要求案主送禮、不可有借貸關係、不可發生性關 係等，這是遵從何種社會工作倫理守則？', '["專業分際", "守密", "追求社會正義", "案主自決"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "f2d4042a3d9b", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099150", "c": "902", "s": "100", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "099", "exam_name": "099年律師、會計師、不動產估價師、專利師、民間之公證人、社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07726', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '年第一次專門職業及技術人員高等考試社會工作師考試試題 類       科：社會工作師 甲、申論題部分：（50分） 不必抄題，作答時請將試題題號及答案依照順序寫在申論試卷上，於本試題上作答者，不予計分。 請以藍、黑色鋼筆或原子筆在申論試卷上作答。', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 99, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07727', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社區工作強調群眾參與為其重要的價值觀，下列何者可回應這個價值觀的說明？', '["雖然無法確保決策能夠符合社區需求，但可提升民主態度和能力", "因為參與是人民的一項權利，並可為群眾自身的需求和感受發聲", "不能避免決策被少數人壟斷和操縱，卻可提升居民歸屬感的需求", "透過社會制度運作，使社區能發揮幫助個別居民自我實現的功能"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07728', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列關於「福利社區化」相關概念的陳述，何者為真？', '["福利社區化其實與「社區總體營造」是一體兩面", "是以社區文史、產業或遊憩為社區工作的切入點", "其相關的法規具有濃厚社會救助的社會福利色彩", "福利社區化企圖結合社會福利體系與社區發展工作"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07729', 'social-worker', 'social-worker-moex-099-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對於社區當中衝突與整合的動力，下列何者為真？', '["舉凡社區當中的文化背景、經濟因素、權力結構或區位關係都可能引發社區衝突", "社區工作者必須防堵社區衝突，因為它是社區歿落的指標，不是社區活力的指標", "所謂的社區整合，是指在社區當中能夠使所有行為標準或信仰價值達到一致性", "不論是積極或消極的社區各派系的領導者，都能讓該派系與社區進行有效整合"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:39+00:00", "source_pdf_sha1": "14a4dbfc792f", "answer_pdf_sha1": "97d8d75691dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
